  ('social-worker-moex-08080', 'social-worker', 'social-worker-moex-098-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童花在電視上的時間大約是在校所做事情的兩倍（Dacey & Travers, 2006）。電視暴力與暴力電玩對兒童 的影響相當大。下列那一陳述是錯誤的？', '["孩子會模仿暴力行為", "暴力會被激發，更容易失控", "暴力不會在代間傳遞", "經常看暴力電視節目會影響其價值觀"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "44ab37d668c4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08081', 'social-worker', 'social-worker-moex-098-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一項不是提供社會化的主要來源？', '["學校", "家庭", "同儕", "兒童福利服務中心"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "44ab37d668c4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
