  ('social-worker-moex-08086', 'social-worker', 'social-worker-moex-098-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據馬斯洛（Maslow, 1962）的需求理論，人類需求的最高級是：', '["自我成長", "自我實現", "性需求", "安全感"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "44ab37d668c4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
